const items = $input.all();

const vars = {};

for (const item of items) {
  const row = item.json;

  const cleanRow = {};
  for (const key of Object.keys(row)) {
    cleanRow[key.trim()] = row[key];
  }

  const name = cleanRow.name;
  const value = cleanRow.value;

  if (name) {
    vars[name] = value;
  }
}

return [
  {
    json: {
      vars
    }
  }
];

const vars = $('Parse Variables').first().json.vars;
const dbConfig = $('Parse DB Config').first().json.dbConfig || {};

const retentionDays = parseInt(dbConfig.retention_days || '60', 10);
const similarityMin = parseFloat(dbConfig.similarity_min || '0.25');
const topK = parseInt(dbConfig.search_top_k || '15', 10);

// ВАЖНО: chat_id берём только из Google Sheet access variables.
// Никакого hardcode и никаких fallback на digest_channel_id.
const chatId = vars.chat_id;
if (!chatId) {
  throw new Error('No chat_id found in Google Sheet access variables');
}

const questions = $input.all()
  .filter(r => r.json.questions && String(r.json.questions).trim().length > 5);

if (questions.length === 0) {
  throw new Error('No questions found in Google Sheet column "questions"');
}

return questions.map((r, i) => ({
  json: {
    queryText: String(r.json.questions).trim(),
    chatId,
    sessionId: 'digest_' + new Date().toISOString().slice(0, 10) + '_' + i,
    vars,
    dbConfig,
    retentionDays,
    similarityMin,
    topK
  }
}));

const embResponse = $input.first().json;
if (embResponse.error) throw new Error('OpenAI error: ' + JSON.stringify(embResponse.error));

const embData = embResponse.data;
if (!embData || !Array.isArray(embData)) throw new Error('No embedding data');

const embRaw = embData[0].embedding;
const vector = Array.isArray(embRaw)
  ? embRaw
  : Object.keys(embRaw).sort((a,b) => Number(a)-Number(b)).map(k => embRaw[k]);

// В loop batchSize=1, поэтому здесь всегда текущий вопрос.
// Берём его из Loop Over Questions, а не из Split Questions.first(), чтобы не залипать на первом вопросе.
const q = $('Loop Over Questions').item.json;

return [{ json: {
  queryText: q.queryText,
  chatId: q.chatId,
  sessionId: q.sessionId,
  queryVector: '[' + vector.join(',') + ']',
  retentionDays: q.retentionDays,
  similarityMin: q.similarityMin,
  topK: q.topK
} }];

const allRows = $input.all().map(i => i.json || {});

// ВАЖНО: Vector Search возвращает до topK строк для ОДНОГО текущего вопроса.
// query_text/chat_id/session_id специально протянуты в SQL в каждой строке,
// поэтому берём метаданные из текущего результата Vector Search, а не через .first()
// из других узлов.
const meta = allRows[0] || {};

const queryText = meta.query_text || '';
const chatId = meta.chat_id || '';
const sessionId = meta.session_id || '';

const rows = allRows.filter(r => r.msg_id);

if (rows.length === 0) {
  return [{
    json: {
      context: '',
      sourcesBlock: '',
      queryText,
      chatId,
      sessionId,
      hasData: false
    }
  }];
}

const byChannel = {};
const sourceIndex = {};
let srcNum = 1;

rows.forEach(r => {
  const rawTitle = r.channel_title || '';
  const ch = String(rawTitle || 'Unknown source').trim();

  if (!byChannel[ch]) {
    byChannel[ch] = [];
    sourceIndex[ch] = srcNum++;
  }

  byChannel[ch].push({
    date: r.msg_date,
    text: String(r.text || '').slice(0, 600)
  });
});

let context = '';
for (const [ch, msgs] of Object.entries(byChannel)) {
  const num = sourceIndex[ch];
  context += `\n=== [${num}] ${ch} ===\n`;
  msgs.forEach(m => {
    context += `[${m.date}] ${m.text}\n`;
  });
}

function fmtDate(raw) {
  try {
    return new Date(raw).toLocaleDateString('ru-RU', {
      day: 'numeric',
      month: 'short'
    });
  } catch (e) {
    return raw;
  }
}

const sourcesList = Object.entries(byChannel).map(([ch, msgs]) => {
  const num = sourceIndex[ch];
  const latest = msgs.map(m => m.date).sort().reverse()[0];
  return `(${num}) ${ch} — ${fmtDate(latest)}`;
});

const sourcesBlock = '\n\n<b>📡 Sources:</b>\n' + sourcesList.join('\n');

return [{
  json: {
    context: context.trim(),
    sourcesBlock,
    sourceIndex,
    queryText,
    chatId,
    sessionId,
    hasData: context.trim().length > 0
  }
}];

return $input.all().map(item => {
  const { queryText, context, chatId, sourcesBlock, sourceIndex, sessionId } = item.json;

  const sourcesList = Object.entries(sourceIndex || {})
    .sort((a, b) => a[1] - b[1])
    .map(([ch, num]) => `(${num}) = ${ch}`)
    .join(', ');

  const systemPrompt = [
    'You are a financial news analyst. Answer ONLY based on the provided Telegram channel data.',
    'Each source block is marked: === [N] Channel Name ===',
    '',
    'Rules:',
    '- Use ONLY provided data, do not invent facts',
    '- Remove ads and duplicates',
    '- Style: Bloomberg/RBC — concise, factual',
    '- After each point add source number: (1), (2)',
    `- Source mapping: ${sourcesList}`,
    '- If data is not relevant — say so explicitly',
    '- Follow the exact FORMAT from the user query (headings with ####, scoring -10 to +10, etc.)',
    '- Current date: ' + new Date().toLocaleDateString('ru-RU')
  ].join('\n');

  const userPrompt = `Query:\n${queryText}\n\nTelegram sources:\n${context}`;

  const body = {
    model: 'gpt-4o-mini',
    temperature: 0.3,
    max_tokens: 1500,
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userPrompt }
    ]
  };

  return { json: { body, chatId, sourcesBlock, sessionId, queryText } };
});

const rawText = $input.first().json?.choices?.[0]?.message?.content || 'No answer received.';
const req = $('Build Digest Request').item.json;
const { chatId, sourcesBlock = '', queryText = '', sessionId = '' } = req;

const safe = rawText
  .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
  .replace(/\*\*(.+?)\*\*/gs, '<b>$1</b>')
  .replace(/#{4}\s*(.+)/g, '<b>$1</b>')
  .replace(/#{3}\s*(.+)/g, '\n<b>$1</b>')
  .replace(/\*(.+?)\*/gs, '<b>$1</b>');

return [{ json: { chatId, text: safe + sourcesBlock, queryText, sessionId } }];

const rows = $input.all();
const dbConfig = {};

for (const r of rows) {
  if (r.json.key) dbConfig[String(r.json.key)] = r.json.value;
}

return [{ json: { dbConfig } }];
